Definition pr1_path_sigma_uncurried `{P : A -> Type} {u v : sig P}
  (pq : { p : u.1 = v.1 & p # u.2 = v.2 })
  : (path_sigma_uncurried _ _ _ pq)..1 = pq.1.

Definition eta_path_sigma_uncurried `{P : A -> Type} {u v : sig P}
  (p : u = v)
  : path_sigma_uncurried _ _ _ (p..1; p..2) = p.

goals.conclusion:
((path_sigma_uncurried P (proj1; proj2) (proj0; proj3) (p; q)) ..1;
(path_sigma_uncurried P (proj1; proj2) (proj0; proj3) (p; q)) ..2) = 
(p; q)

match
  path_sigma_uncurried_contra P (proj1; proj2) (proj0; proj3) (p; q) in
  (_ = s) return {p0 : proj1 = s.1 & proj2 = transport P p0^ s.2}
with
| 1 => (1; 1)
end = (p; q)

match
  path_sigma_uncurried_contra P (proj1; proj2) (proj1; proj3) (1; q) in
  (_ = s) return {p : proj1 = s.1 & proj2 = transport P p^ s.2}
with
| 1 => (1; 1)
end = (1; q)

transport (fun x : A => {y : B & C x y}) 1 (proj1; proj2) =
((proj1; proj2).1;
transport (fun x : A => C x (proj1; proj2).1) 1 (proj1; proj2).2)

