Definition transport_sigma_' {A : Type} {B C : A -> Type}
  {D : forall a:A, B a -> C a -> Type}
  {x1 x2 : A} (p : x1 = x2)
  (yzw : { y : B x1 & { z : C x1 & D x1 y z } })
  : transport (fun x => { y : B x & { z : C x & D x y z } }) p yzw
    = (p # yzw.1 ; p # yzw.2.1 ; transportD2 _ _ _ p yzw.1 yzw.2.1 yzw.2.2).

goals.conclusion:
transport (fun x : A => {y : B x & {z : C x & D x y z}}) p yzw =
(transport B p yzw.1; transport C p (yzw.2).1;
transportD2 B C D p yzw.1 (yzw.2).1 (yzw.2).2)

transport (fun x : A => {y : B x & {z : C x & D x y z}}) p yzw =
(transport B p yzw.1; transport C p (yzw.2).1;
transportD2 B C D p yzw.1 (yzw.2).1 (yzw.2).2)

transport (fun x : A => {y : B x & {z : C x & D x y z}}) 1 yzw =
(transport B 1 yzw.1; transport C 1 (yzw.2).1;
transportD2 B C D 1 yzw.1 (yzw.2).1 (yzw.2).2)

